import{_ as a,o as i,c as l,S as s}from"./chunks/framework.DZlzLDBr.js";const u=JSON.parse('{"title":"Flags","description":"","frontmatter":{},"headers":[],"relativePath":"Flags.md","filePath":"Flags.md","lastUpdated":null}'),o={name:"Flags.md"};function t(n,e,r,d,c,p){return i(),l("div",null,[...e[0]||(e[0]=[s(`<h1 id="flags" tabindex="-1">Flags <a class="header-anchor" href="#flags" aria-label="Permalink to &quot;Flags&quot;">​</a></h1><p>Last modified: 04/03/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Sprout supports inline circle flags inside card text fields using token syntax. Flag assets are provided by <a href="https://github.com/HatScripts/circle-flags" target="_blank" rel="noreferrer">HatScripts/circle-flags</a> (MIT).</p><p>Supported token formats:</p><ul><li><code>{{es}}</code></li></ul><p>These render as small circular flag icons with diameter matching the current text size.</p><h2 id="full-code-reference" tabindex="-1">Full code reference <a class="header-anchor" href="#full-code-reference" aria-label="Permalink to &quot;Full code reference&quot;">​</a></h2><p>Use <a href="./Flag-Codes">Flag-Codes</a> for full code tables:</p><ul><li>Country and territory codes</li><li>State/region codes grouped by country (country in first column)</li><li>Language codes</li></ul><h2 id="where-flags-work" tabindex="-1">Where flags work <a class="header-anchor" href="#where-flags-work" aria-label="Permalink to &quot;Where flags work&quot;">​</a></h2><p>Flags are supported in all text content fields:</p><ul><li><code>T</code> (title)</li><li><code>Q</code> / <code>RQ</code> / <code>CQ</code> / <code>MCQ</code> / <code>OQ</code> (question/stem fields)</li><li><code>A</code> and <code>O</code> (answers/options)</li><li>Ordered-question steps (<code>1</code>, <code>2</code>, <code>3</code>, ...)</li><li><code>I</code> (extra information)</li></ul><p>Flags are <strong>not</strong> supported in <code>G</code> (groups).</p><h2 id="editing-behavior" tabindex="-1">Editing behavior <a class="header-anchor" href="#editing-behavior" aria-label="Permalink to &quot;Editing behavior&quot;">​</a></h2><p>In card editors and browser inputs:</p><ul><li>when the field is focused, you see raw tokens (for example <code>{{gb}}</code>)</li><li>when the field loses focus, tokens render as flag icons</li></ul><p>This matches Sprout’s existing image-preview editing style.</p><h2 id="display-behavior" tabindex="-1">Display behavior <a class="header-anchor" href="#display-behavior" aria-label="Permalink to &quot;Display behavior&quot;">​</a></h2><p>Flags render in:</p><ul><li>Study mode</li><li>Widget mode</li><li>Gatekeeper mode</li><li>Reading view / pretty-card rendering</li></ul><p>They are also used by <a href="./Text-to-Speech">TTS</a> when flag-aware routing is enabled.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><p>Basic language-pair card:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q | {{es}} Hola |</span></span>
<span class="line"><span>A | {{gb}} Hello |</span></span></code></pre></div><p>State card example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q | {{us-ca}} California |</span></span>
<span class="line"><span>A | {{gb}} West Coast, United States |</span></span></code></pre></div><h2 id="syntax-and-compatibility-notes" tabindex="-1">Syntax and compatibility notes <a class="header-anchor" href="#syntax-and-compatibility-notes" aria-label="Permalink to &quot;Syntax and compatibility notes&quot;">​</a></h2><ul><li>Sprout keeps cloze syntax untouched (<code>{{c1::...}}</code>, <code>{{c2::...}}</code>, etc.).</li><li>Invalid flag tokens are left as plain text.</li><li>Flags use circle-flag asset codes (country/region style codes), not free-form language names.</li></ul><h2 id="offline-cache-behavior" tabindex="-1">Offline cache behavior <a class="header-anchor" href="#offline-cache-behavior" aria-label="Permalink to &quot;Offline cache behavior&quot;">​</a></h2><p>Flags are fetched on demand and cached locally.</p><ul><li>first render of a new code may require network</li><li>after fetch, cached data is used offline</li><li>cache is bounded (LRU-style trimming) to avoid unbounded growth</li></ul><p>This keeps plugin size small while still supporting offline use after first load.</p><h2 id="tts-behavior-with-flags" tabindex="-1">TTS behavior with flags <a class="header-anchor" href="#tts-behavior-with-flags" aria-label="Permalink to &quot;TTS behavior with flags&quot;">​</a></h2><p>When <strong>Settings → Audio → Flag-aware routing → Use flags for language and accent</strong> is enabled:</p><ul><li><code>{{es}}</code> routes speech to Spanish voices.</li><li>A single flag can apply to the full spoken text (not position-dependent).</li><li>Multiple flags in one field use segmented inline voice switching.</li></ul><p>Optional setting:</p><ul><li><strong>Speak language name before flag segments</strong> adds spoken labels before each flag-switched segment. <ul><li>Example labels are language names such as <strong>English</strong> or <strong>Spanish</strong>.</li><li>Regional accent selection still applies (for example UK/US English voices).</li></ul></li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Use short, consistent codes in language decks (<code>{{es}}</code>, <code>{{fr}}</code>, <code>{{de}}</code>).</li><li>If you prefer UK/US distinction in English prompts, use explicit tokens such as <code>{{gb}}</code> or <code>{{us}}</code>.</li><li>Combine flags with TTS for mixed-language cards, for example <code>{{es}}</code> question + <code>{{gb}}</code> answer.</li></ul>`,40)])])}const g=a(o,[["render",t]]);export{u as __pageData,g as default};
